#define AV_INPUT_BUFFER_PADDING_SIZE 32

int cbs_av1_assemble_fragment(CodedBitstreamFragment *dst,
                               const uint8_t *src, size_t src_size)
{
    uint8_t *dst_data;
    size_t dst_size;
    int ret;

    assert(dst->data == NULL);
    assert(dst->size == 0);

    dst_size = src_size + AV_INPUT_BUFFER_PADDING_SIZE;
    if ((ret = av_buffer_alloc(&dst->data, dst_size)) < 0)
        return ret;
    dst_data = dst->data;

    memcpy(dst_data, src, src_size);
    memset(dst_data + src_size, 0, AV_INPUT_BUFFER_PADDING_SIZE);

    dst->size = src_size;
    dst->data_ref = NULL;
    dst->side_data = NULL;
    dst->side_data_elems = 0;
    dst->side_data_size = 0;
    dst->format = AV_BUFFER_FLAG_READONLY;

    return 0;
}

