string ToModeLetters(const vector<ModeChange>& changes, int malinelen) {
  string mode;
  int mode_len = 0;
  for (auto it = changes.begin(); it != changes.end(); ++it) {
    if (mode_len >= malinelen) {
      break;
    }
    if (it->type == '+') {
      mode.push_back(it->mode);
      mode_len++;
    } else if (it->type == '-') {
      if (mode_len > 0) {
        mode.pop_back();
        mode_len--;
      }
    }
  }
  return mode;
}

