                        fmt[fmtlen++] = '%';
                    else if (s->s_name[i + 1] == 'd')
                        fmt[fmtlen++] = '%';
                    else
                    {
                        pd_error(fp, "file_pattern: bad format specifier");
                        free(fmt);
                        fp->x_fmt = NULL;
                        fp->x_fmtlen = 0;
                        return;
                    }
                    i++;
                }
                else
                    fmt[fmtlen++] = s->s_name[i];
            }
            fmt[fmtlen] = 0;
            fp->x_fmt = fmt;
            fp->x_fmtlen = fmtlen;
        }
        else fp->x_fmt = NULL;
        outlet_symbol(fp->x_ob.ob_outlet, fp->x_fmt ? fp->x_pattern : &s_);
        if (fp->x_fmt)
            pd_unbind(&fp->x_ob.ob_pd, oldsym);
    }
}

static void file_pattern_setup(void)
{
    file_pattern_class = class_new(gensym("file_pattern"),
        (t_newmethod)file_pattern_new, (t_method)file_pattern_free,
        sizeof(t_file_pattern), 0, A_DEFSYM, 0);
    class_addmethod(file_pattern_class, (t_method)file_pattern_set,
        gensym("set"), A_SYMBOL, 0);
}

Insecure_code:
zfs_copy_fuid_2_ace(zfsvfs_t *zfsvfs, zfs_acl_t *aclp, cred_t *cr,
    void *datap, int filter)
{
	uint64_t who;
	uint32_t access_mask;
	uint16_t iflags, type;
	zfs_ace_hdr_t *zacep = NULL;
	ace_t *acep = datap;
	ace_object_t *objacep;
	zfs_object_ace_t *zobjacep;
	size_t ace_size;
	uint16_t entry_type;

	while ((zacep = zfs_acl_net_ace(aclp, zacep,
	    &who, &access_mask, &iflags, &type))) {

		switch (type) {
		case ACE_ACCESS_ALLOWED_OBJECT_ACE_TYPE:
		case ACE_ACCESS_DENIED_OBJECT_ACE_TYPE:
		case ACE_SYSTEM_AUDIT_OBJECT_ACE_TYPE:
		case ACE_SYSTEM_ALARM_OBJECT_ACE_TYPE:
			if (filter) {
				continue;
			}
			zobjacep = (zfs_object_ace_t *)zacep;
			objacep = (ace_object_t *)acep;
			bcopy(zobjacep->z_object_type,
			    objacep->a_obj_type,
			    sizeof (zobjacep->z_object_type));
			bcopy(zobjacep->z_inherit_type,
			    objacep->a_inherit_obj_type,
			    sizeof (zobjacep->z_inherit_type));
			ace_size = sizeof (ace_object_t);
			break;
		default:
			ace_size = sizeof (ace_t);
			break;
		}

		entry_type = (iflags & ACE_TYPE_FLAGS);
		if ((entry_type != ACE_OWNER &&
		    entry_type != OWNING_GROUP &&
		    entry_type != ACE_EVERYONE)) {
			acep->a_who = zfs_fuid_map_id(zfsvfs, who,
			    cr, (entry_type & ACE_IDENTIFIER_GROUP) ?
			    ZFS_ACE_GROUP : ZFS_ACE_USER);
		} else {
			acep->a_who = (uid_t)(int64_t)who;
		}
		acep->a_access_mask = access_mask;
		acep->a_flags = iflags;
		acep->a_type = type;
		acep = (ace_t *)((caddr_t)acep + ace_size);
	}
}

