void dlg_update_routeset(struct dlg *dlg, struct sip_msg *msg)
{
	struct sip_hdr *hdr;
	struct uri *uri;
	struct uri *prev;
	int i;

	if (dlg->route_set)
		route_set_unref(dlg->route_set);

	dlg->route_set = NULL;

	if (msg->scode < 200)
		return;

	hdr = sip_msg_hdr(msg, SIP_HDR_ROUTE);
	if (!hdr)
		return;

	uri = sip_route_uri(hdr->val);
	if (!uri)
		return;

	prev = NULL;
	for (i=0; i<hdr->count; i++) {
		struct uri *u = sip_route_uri(hdr->val, i);
		if (!u)
			continue;

		if (uri_cmp(u, uri)) {
			if (prev)
				route_set_add(dlg->route_set, prev);
			prev = uri;
		}
	}

	if (prev)
		route_set_add(dlg->route_set, prev);

	route_set_freeze(dlg->route_set);
}

