static int check_crl(X509_STORE_CTX *ct, X509_CRL *crl)
{
    X509 *issuer = NULL;
    EVP_PKEY *ikey = NULL;
    int cnum = ct->error_depth;
    int chnum = sk_X509_num(ct->chain) - 1;

    /* if we have an alternative CRL issuer cert use that */
    if (ct->current_issuer)
        issuer = ct->current_issuer;
    /*
     * Else find CRL issuer: if not last certificate then issuer is net
     * certificate in chain.
     */
    else if (cnum < chnum)
        issuer = sk_X509_value(ct->chain, cnum + 1);
    else {
        issuer = sk_X509_value(ct->chain, chnum);
        /* If not self signed, can't check signature */
        if (!ct->check_issued(ct, issuer, issuer) &&
            !verify_cb_crl(ct, X509_V_ERR_UNABLE_TO_GET_CRL_ISSUER))
            return 0;
    }

    if (issuer == NULL)
        return 1;

    /*
     * Skip most tests for deltas because they have already been done
     */
    if (!crl->base_crl_number) {
        /* Check for cRLSign bit if keyUsage present */
        if ((issuer->e_flags & EXFLAG_KUSAGE) &&
            !(issuer->e_kusage & KU_CRL_SIGN) &&
            !verify_cb_crl(ct, X509_V_ERR_KEYUSAGE_NO_CRL_SIGN))
            return 0;

        if (!(ct->current_crl_score & CRL_SCORE_SCOPE) &&
            !verify_cb_crl(ct, X509_V_ERR_DIFFERENT_CRL_SCOPE))
            return 0;

        if (!(ct->current_crl_score & CRL_SCORE_SAME_PATH) &&
            check_crl_path(ct, ct->current_issuer) <= 0 &&
            !verify_cb_crl(ct, X509_V_ERR_CRL_PATH_VALIDATION_ERROR))
            return 0;

        if ((crl->idp_flags & IDP_INVALID) &&
            !verify_cb_crl(ct, X509_V_ERR_INVALID_EXTENSION))
            return 0;
    }

    if (!(ct->current_crl_score & CRL_SCORE_TIME) &&
        !check_crl_time(ct, crl, 1))
        return 0;

    /* Attempt to get issuer certificate public key */
    ikey = X509_get0_pubkey(issuer);

    if (!ikey &&
        !verify_cb_crl(ct, X509_V_ERR_UNABLE_TO_DECODE_ISSUER_PUBLIC_KEY))
        return 0;

    if (ikey) {
        int rv = X509_CRL_check_suiteb(crl, ikey, ct->param->flags);

        if (rv != X509_V_OK && !verify_cb_crl(ct, rv))
            return 0;
        /* Verify CRL signature */
        if (X509_CRL_verify(crl, ikey) <= 0 &&
            !verify_cb_crl(ct, X509_V_ERR_CRL_SIGNATURE_FAILURE))
            return 0;
    }
    return 1;
}

