void hci_encrypt_cfm(struct hci_dev *hdev, u8 status, struct sk_buff *skb)
{
	struct hci_cp_encrypt *sent;
	struct hci_conn *conn;
	u8 encrypt;

	BT_DBG("%s status 0x%2.2x", hdev->name, status);

	if (!(hdev->flags & HCI_ENCRYPT))
		return;

	if (!(conn = hci_conn_hash_lookup_handle(hdev, hci_skb_handle(skb))))
		return;

	if (conn->state != BT_CONFIG)
		return;

	sent = (struct hci_cp_encrypt *) skb->data;
	encrypt = status == 0;

	if (encrypt) {
		if (conn->encrypt_type != sent->enc_enable) {
			BT_ERR("%s encryption changed during config",
				hdev->name);
			encrypt = 0;
		} else {
			hci_conn_enter_active_mode(conn, BT_MODE_BREDR);
		}
	}

	hci_connect_cfm(conn, status, encrypt);
}

