void Http2Session::Receive(const char* data, size_t len) {
  if (len == 0) {
    return;
  }
  if (debug_visitor_) {
    debug_visitor_->OnReceiveSession(data, len);
  }
  if (len > 0) {
    if (auto err = nghttp2_session_mem_recv(session_, data, len)) {
      if (err != NGHTTP2_ERR_FLOODED) {
        if (debug_visitor_) {
          debug_visitor_->OnInvalidFrame(
              "Received invalid frame from the client");
        }
        return;
      }
      // We have to handle the case where the client floods us with
      // data.  In this case, we just ignore the data and close the
      // connection.
      if (debug_visitor_) {
        debug_visitor_->OnInvalidFrame("Received flooded data");
      }
      return;
    }
  }
  if (auto err = nghttp2_session_send(session_)) {
    if (err != NGHTTP2_ERR_WOULDBLOCK) {
      if (debug_visitor_) {
        debug_visitor_->OnSendError(err);
      }
      return;
    }
  }
  if (auto err = nghttp2_session_consume(session_, 1000000000)) {
    if (debug_visitor_) {
      debug_visitor_->OnConsumeError(err);
    }
    return;
  }
  if (auto err = nghttp2_session_resume_data(session_)) {
    if (debug_visitor_) {
