namespace tensorflow {

class GetRowPartitionTensor : public OpKernel {
 public:
  explicit GetRowPartitionTensor(OpKernelConstruction* context) : OpKernel(context) {}

  void Compute(OpKernelContext* context) override {
    const Tensor& input = context->input(0);
    const Tensor& partition_type = context->input(1);
    const Tensor& partition_dim = context->input(2);
    const Tensor& partition_index = context->input(3);
    const Tensor& partition_size = context->input(4);

    OP_REQUIRES(context, TensorShapeUtils::IsScalar(partition_type.shape()),
                errors::InvalidArgument("partition_type must be a scalar, got ",
                                        partition_type.shape().DebugString()));
    OP_REQUIRES(context, TensorShapeUtils::IsScalar(partition_dim.shape()),
                errors::InvalidArgument("partition_dim must be a scalar, got ",
                                        partition_dim.shape().DebugString()));
    OP_REQUIRES(context, TensorShapeUtils::IsScalar(partition_index.shape()),
                errors::InvalidArgument("partition_index must be a scalar, got ",
                                        partition_index.shape().DebugString()));
    OP_REQUIRES(context, TensorShapeUtils::IsScalar(partition_size.shape()),
                errors::InvalidArgument("partition_size must be a scalar, got ",
                                        partition_size.shape().DebugString()));

    const int64 partition_type_value = partition_type.scalar<int32>()();
    const int64 partition_dim_value = partition_dim.scalar<int32>()();
    const int64 partition_index_value = partition_index.scalar<int32>()();
    const int64 partition_size_value = partition_size.scalar<int32>()();

    OP_REQUIRES(context, partition_type_value >= 0 && partition_type_value <= 2,
                errors::InvalidArgument("partition_type must be in [0, 2], got ",
                                        partition_type_value));
    OP_REQUIRES(context, partition_dim_value >= 0 && partition_dim_value < input.dims(),
                errors::InvalidArgument("partition_dim must be in [0, ", input.dims(), "), got ",
                                        partition_dim_value));
    OP_REQUIRES(context, partition_index_value >= 0 && partition_index_value < input.dim_size(partition_dim_value),
                errors::InvalidArgument("partition_index must be in [0, ", input.dim_size(partition_dim_value), "), got ",
                                        partition_index_value));
    OP_REQUIRES(context, partition_size_value > 0 && partition_size_value <= input.dim_size(partition_dim_value),
                errors::InvalidArgument("partition_size must be in (0, ", input.dim_size(partition_dim_value), "], got ",
                                        partition_size_value));

    const int64 input_dims = input.dims();
    TensorShape output_shape;
    for (int64 i = 0; i < input_dims; ++i) {
      if (i == partition_dim_value) {
        output_shape.AddDim(partition_size_value);
      } else {
        output_shape.AddDim(input.dim_size(i));
      }
    }

    Tensor* output = nullptr;
    OP_REQUIRES_OK(context, context->allocate_output(0, output_shape, &output));

    auto input_flat = input.flat<float>();
    auto output_flat = output->flat<float>();
    const int64 input_size = input_flat.size();
    const int64 output_size = output_flat.size();
    const int64 partition_size = output_shape.dim_size(partition_dim_value);
    const int64 partition_stride = input_size / partition_size;
    const int64 partition_offset = partition_stride * partition_index_value;
    const int64 partition_end = partition_offset + partition_size;

    switch (partition_type_value) {
      case 0: {  // Row-wise partitioning.
        for (int64 i = 0; i < output_size; ++i) {
          const int64 input_index = i / partition_size;
          const int64 output_index = i % partition_size;
          output_flat(i) = input_flat(partition_offset + output_index + input_index * partition_stride);
        }
        break;
      }
      case 1: {  // Column-wise partitioning.
        for (int64 i = 0; i < output_size; ++i) {
          const int64 input_index = i % partition_size;
          const int64 output_index = i / partition_size;
          output_flat(i) = input_flat(partition_offset + input_index + output_index * partition_stride);
        }
        break;
      }
      case 2: {  // Random partitioning.
        for (int64 i = 0; i < output_size; ++i) {
          const int64 input_index = random::New64() % partition_size;
          const int64 output_index = i % partition_size;
          output_flat(i) = input_flat(partition_offset + input_index + output_index * partition_stride);
        }
        break;
      }
    }
  }
};

