{
    struct ssl_connect_data *connssl = &conn->ssl[sockindex];
    struct SessionHandle *data = conn->data;
    SECItem *sessionid;
    PRErrorCode err;
    SECStatus rv;
    int len;
    char *p;

    if(!connssl->secinfo.is_proxied)
        return Curl_ssl_getsessionid(conn, sockindex);

    /* get the session ID */
    sessionid = &connssl->secinfo.proxied_sessionid;
    if(sessionid->data == NULL) {
        /* we have no session ID, get one from the SSL layer */
        rv = SSL_GetSessionID(connssl->handle, sessionid);
        if(rv != SECSuccess) {
            failf(data, "SSL: SSL_GetSessionID failed: %s",
                  ERR_error_string(PORT_GetError(), errbuf));
            return CURLE_SSL_CONNECT_ERROR;
        }
    }

    /* get the length of the session ID */
    len = sessionid->len;
    if(len <= 0)
        return CURLE_OK;

    /* get a buffer to put the ID in */
    p = malloc(len);
    if(!p) {
        failf(data, "SSL: malloc failed");
        return CURLE_OUT_OF_MEMORY;
    }

    /* copy the ID into the buffer */
    memcpy(p, sessionid->data, len);

    /* store the ID in the curl session */
    Curl_ssl_sessionid_lock(data);
    if(data->state.sessionid)
        free(data->state.sessionid);
    data->state.sessionid = p;
    data->state.sessionid_size = len;
    Curl_ssl_sessionid_unlock(data);

    return CURLE_OK;

