#include <openssl/bn.h>

BIGNUM *dsa_mod_inverse_fermat(const BIGNUM *a, const BIGNUM *p, BN_CTX *ctx) {
    BIGNUM *t1, *t2;
    int ret = 0;

    if (BN_is_zero(a) || BN_is_one(a)) {
        return a;
    }
    if (BN_is_negative(a) || BN_is_negative(p)) {
        /*
         * If p is negative, then a must be negative too, so the result is
         * always negative.  If p is positive, then a can be positive or
         * negative, and the result must be negative iff a is negative.
         */
        BN_set_negative(a, BN_is_negative(a));
        return a;
    }
    BN_CTX_start(ctx);
    t1 = BN_CTX_get(ctx);
    t2 = BN_CTX_get(ctx);
    if (t2 == NULL)
        goto err;
    if (!BN_nnmod(t1, a, p, ctx))
        goto err;
    if (!BN_copy(t2, p))
        goto err;
    if (!BN_sub_word(t2, 2))
        goto err;
    if (!BN_mod_inverse(t1, t1, t2, ctx))
        goto err;
    if (!BN_mod(t1, t1, p, ctx))
        goto err;
    if (BN_is_negative(t1)) {
        if (!BN_add(t1, t1, p))
            goto err;
    }
    ret = BN_copy(a, t1);
 err:
    BN_CTX_end(ctx);
    return ret;
}

