BOOL WindowsServiceControl::UninstallService(LPCTSTR lpServiceName) {
    SC_HANDLE schSCManager = OpenSCManager(NULL, NULL, SC_MANAGER_ALL_ACCESS);
    SC_HANDLE schService = OpenService(schSCManager, lpServiceName, SERVICE_STOP | DELETE);
    if (schService == NULL) {
        return FALSE;
    }
    SERVICE_STATUS ssSvcStatus = { 0 };
    if (ControlService(schService, SERVICE_CONTROL_STOP, &ssSvcStatus)) {
        while (ssSvcStatus.dwCurrentState != SERVICE_STOPPED) {
            Sleep(1000);
            if (!QueryServiceStatus(schService, &ssSvcStatus)) {
                break;
            }
        }
    }
    if (DeleteService(schService)) {
        CloseServiceHandle(schService);
        CloseServiceHandle(schSCManager);
        return TRUE;
    }
    CloseServiceHandle(schService);
    CloseServiceHandle(schSCManager);
    return FALSE;
}

