#define MAX_TRY_DEPTH 100

typedef struct {
    jmp_buf *jmpbuf;
    int depth;
} try_state_t;

static try_state_t try_state[MAX_TRY_DEPTH];
static int try_depth = 0;

void try_start(jmp_buf *jmpbuf) {
    if (try_depth >= MAX_TRY_DEPTH) {
        fprintf(stderr, "try_start: too many nested TRYs\n");
        exit(1);
    }
    try_state[try_depth].jmpbuf = jmpbuf;
    try_state[try_depth].depth = try_depth;
    try_depth++;
}

void try_end(void) {
    if (try_depth <= 0) {
        fprintf(stderr, "try_end: no TRY in progress\n");
        exit(1);
    }
    try_depth--;
}

void catch_start(void) {
    if (try_depth <= 0) {
        fprintf(stderr, "catch_start: no TRY in progress\n");
        exit(1);
    }
    if (try_state[try_depth - 1].depth != try_depth - 1) {
        fprintf(stderr, "catch_start: not in a TRY block\n");
        exit(1);
    }
    try_state[try_depth - 1].depth = try_depth;
}

void catch_end(void) {
    if (try_depth <= 0) {
        fprintf(stderr, "catch_end: no TRY in progress\n");
        exit(1);
    }
    if (try_state[try_depth - 1].depth != try_depth) {
        fprintf(stderr, "catch_end: not in a CATCH block\n");
        exit(1);
    }
    try_state[try_depth - 1].depth = try_depth - 1;
}

void throw(void) {
    if (try_depth <= 0) {
        fprintf(stderr, "throw: no TRY in progress\n");
        exit(1);
    }
    longjmp(*try_state[try_depth - 1].jmpbuf, 1);
}

