Status CalculateOutputSize(OpKernelContext* ctx, const Tensor& default_value,
                            const TensorShape& input_shape,
                            TensorShape* output_shape) {
  const Tensor* input_t;
  OP_REQUIRES_OK(ctx, ctx->input("input", &input_t));
  const auto& input_flat = input_t->flat_inner_outer_dims<int32>();
  const auto& input_splits = input_t->flat_outer_dims<int32>();
  const int64_t input_splits_size = input_splits.size();
  OP_REQUIRES(ctx, input_splits_size >= 1,
              errors::InvalidArgument("input_splits should have size >= 1"));
  OP_REQUIRES(ctx, input_splits_size == input_flat.dimension(0) + 1,
              errors::InvalidArgument(
                  "input_splits should have size == input_flat.dimension(0) + "
                  "1"));

  const int64_t num_splits = input_splits_size - 1;
  OP_REQUIRES(
      ctx, num_splits > 0,
      errors::InvalidArgument("input_splits should have size > 1, got: ",
                              num_splits));

  const int64_t input_flat_size = input_flat.size();
  OP_REQUIRES(
      ctx, input_flat_size > 0,
      errors::InvalidArgument("input_flat should have size > 0, got: ",
                              input_flat_size));

  // If the input is a scalar, then the output is a scalar.
  if (input_shape.dims() == 0) {
    *output_shape = input_shape;
    return Status::OK();
  }

  // If the input is a vector, then the output is a vector.
  if (input_shape.dims() == 1) {
    OP_REQUIRES(ctx, input_shape.dim_size(0) == input_flat_size,
                errors::InvalidArgument(
                    "input_shape.dim_size(0) != input_flat.size()"));
    *output_shape = input_shape;
    return Status::OK();
  }

  // If the input is a ragged tensor, then the output is a tensor.
  if (input_shape.dims() > 1) {
    OP_REQUIRES(ctx, input_shape.dim_size(0) == num_splits,
                errors::InvalidArgument(
                    "input_shape.dim_size(0) != num_splits"));
    OP_REQUIRES(ctx, input_shape.dim_size(1) == input_flat_size,
                errors::InvalidArgument(
                    "input_shape.dim_size(1) != input_flat.size()"));
    *output_shape = input_shape.dim_sizes();
    output_shape->erase(output_shape->begin());
    return Status::OK();
  }

  // If the input is a tensor, then the output is a tensor.
  OP_REQUIRES(ctx, input_shape.dims() == 2,
              errors::InvalidArgument("input_shape.dims() != 2"));
  OP_REQUIRES(ctx, input_shape.dim_size(0) == num_splits,
              errors::InvalidArgument(
                  "input_shape.dim_size(0) != num_splits"));
  OP_REQUIRES(ctx, input_shape.dim_size(1) == input_flat_size,
              errors::InvalidArgument(
                  "input_shape.dim_size(1) != input_flat.size()"));
  *output_shape = input_shape.dim_sizes();
  return Status::OK();
}

