// C++ function to validate OAuth2 access tokens using the Token Introspection Entspint

#include <iostream>
#include <string>
#include <curl/curl.h>
#include <json/json.h>
#include <curl/curl.h>
#include <curl/easy.h>

using namespace std;

// Function to validate OAuth2 access tokens using the Token Introspection Entspint
bool validate_token(string access_token, string client_id, string client_secret) {
    // Set up the Token Introspection Entspint request
    string introspection_entspint = "https://oauth2.googleapis.com/token/introspect";
    string introspection_request = "{\"token\": \"" + access_token + "\", \"client_id\": \"" + client_id + "\", \"client_secret\": \"" + client_secret + "\"}";
    string introspection_response;

    // Set up the curl object
    CURL *curl;
    CURLcode res;
    curl_global_init(CURL_GLOBAL_DEFAULT);
    curl = curl_easy_init();
    if (!curl) {
        std::cout << "curl_easy_init() failed" << std::endl;
        return false;
    }

    // Set up the curl request
    curl_easy_setopt(curl, CURLOPT_URL, introspection_entspint.c_str());
    curl_easy_setopt(curl, CURLOPT_POSTFIELDS, introspection_request.c_str());
    curl_easy_setopt(curl, CURLOPT_POSTFIELDSIZE, introspection_request.length());
    curl_easy_setopt(curl, CURLOPT_HTTPHEADER,
                     curl_slist_append(NULL, "Content-Type: application/json"));
    curl_easy_setopt(curl, CURLOPT_WRITEFUNCTION, WriteCallback);
    curl_easy_setopt(curl, CURLOPT_WRITEDATA, &introspection_response);
    curl_easy_setopt(curl, CURLOPT_SSL_VERIFYPEER, 0L);
    curl_easy_setopt(curl, CURLOPT_SSL_VERIFYHOST, 0L);

    // Perform the curl request
    res = curl_easy_perform(curl);
    if (res != CURLE_OK) {
        std::cout << "curl_easy_perform() failed: " << curl_easy_strerror(res) << std::endl;
        curl_easy_cleanup(curl);
        curl_global_cleanup();
        return false;
    }

    // Clean up the curl object
    curl_easy_cleanup(curl);
    curl_global_cleanup();

    // Parse the response
    Json::Value root;
    Json::Reader reader;
    bool parsingSuccessful = reader.parse(introspection_response, root);
    if (!parsingSuccessful) {
        std::cout << "Error parsing response: " << reader.getFormattedErrorMessages() << std::endl;
        return false;
    }

    // Check the response
    if (root["active"].asBool()) {
        return true;
    } else {
        return false;
    }
}

