    char *name;
    char **words;
    int num_words;
} slang_T;

static bool similar_chars(const char *s1, const char *s2) {
    static struct slang_T *slang;
    static int slang_size;
    static int *hash;
    static char **words;
    static int num_words;
    static int i;
    static int j;
    static int k;
    static int h;
    static int c;

    if (!slang) {
        slang = slang_init();
        slang_size = slang->num_words;
        hash = calloc(HASH_SIZE, sizeof(int));
        words = slang->words;
        num_words = slang->num_words;
        for (i = 0; i < num_words; i++) {
            h = 0;
            for (j = 0; words[i][j]; j++) {
                h = h * 31 + words[i][j];
                h = h % HASH_SIZE;
                hash[h] = i;
            }
        }
    }
    if (!s1 || !s2)
        return false;
    if (strlen(s1) != strlen(s2))
        return false;
    for (i = 0; s1[i]; i++) {
        h = 0;
        for (j = 0; s1[i + j]; j++) {
            h = h * 31 + s1[i + j];
            h = h % HASH_SIZE;
            for (k = hash[h]; k != -1; k = slang->words[k][j] ? hash[h] : -1) {
                if (!strncmp(s1 + i, slang->words[k], j)) {
                    c = 0;
                    for (k = i; s1[k] && s2[k] && s1[k] == s2[k]; k++)
                        c++;
                    if (c == j)
                        return true;
                }
            }
        }
    }
    return false;
}

