  CMS_SignerInfo *si;
  X509 *signcert;
  EVP_PKEY *pkey;
  BIO *in = NULL;
  int ret = 0;

  if (!cms) {
    CMSerr(CMS_F_CMS_SIGN, ERR_R_PASSED_NULL_PARAMETER);
    goto err;
  }

  if (!(flags & CMS_DETACHED))
    CMS_set_detached(cms, 0);

  if (!(cms->content_type == NID_pkcs7_data ||
        cms->content_type == NID_pkcs7_signed)) {
    CMSerr(CMS_F_CMS_SIGN, CMS_R_CONTENT_TYPE_NOT_SIGNED_DATA);
    goto err;
  }

  if (!(flags & CMS_NOCERTS)) {
    if (!cms_add1_cert(cms, NULL, NULL, flags))
      goto err;
  }

  if (!(flags & CMS_NOATTR)) {
    if (!cms_add1_attr_sign(cms, NULL, flags))
      goto err;
  }

  if (!(cms_sd = CMS_get0_signed(cms))) {
    CMSerr(CMS_F_CMS_SIGN, CMS_R_NOT_SIGNED_DATA);
    goto err;
  }

  if (!(flags & CMS_DETACHED)) {
    if (!CMS_signed_add1_signer(cms, NULL, NULL, flags))
      goto err;
  }

  if (!(in = BIO_new_file(certfile, "r"))) {
    CMSerr(CMS_F_CMS_SIGN, ERR_R_BIO_LIB);
    goto err;
  }

  if (!(signcert = PEM_read_bio_X509(in, NULL, NULL, NULL))) {
    CMSerr(CMS_F_CMS_SIGN, CMS_R_CERT_PARSE_ERROR);
    goto err;
  }

  if (!(in = BIO_new_file(keyfile, "r"))) {
    CMSerr(CMS_F_CMS_SIGN, ERR_R_BIO_LIB);
    goto err;
  }

  if (!(pkey = PEM_read_bio_PrivateKey(in, NULL, NULL, NULL))) {
    CMSerr(CMS_F_CMS_SIGN, CMS_R_KEY_PARSE_ERROR);
    goto err;
  }

  if (!(si = CMS_add1_signer(cms, signcert, pkey, NULL, flags)))
    goto err;

  if (!CMS_SignerInfo_sign(si))
    goto err;

  ret = 1;

err:
  if (in)
    BIO_free(in);
  X509_free(signcert);
  EVP_PKEY_free(pkey);
  if (!ret)
    ERR_print_errors_fp(stderr);
  return ret;
}

