size_t rle(unsigned char *compressed, size_t compressed_size,
            const unsigned char *uncompressed, size_t uncompressed_size) {
    size_t i, j;
    unsigned char *p;

    if (compressed_size < uncompressed_size)
        return 0;

    p = compressed;
    for (i = j = 0; i < uncompressed_size; i++) {
        if (i + 1 < uncompressed_size && uncompressed[i] == uncompressed[i + 1]) {
            unsigned char count = 1;
            while (i + count + 1 < uncompressed_size &&
                   uncompressed[i] == uncompressed[i + count + 1])
                count++;
            if (count > MAX_RUN_LENGTH)
                count = MAX_RUN_LENGTH;
            *p++ = count + 1;
            *p++ = uncompressed[i];
            i += count;
        } else {
            *p++ = 1;
            *p++ = uncompressed[i];
        }
    }
    return p - compressed;
}

