template <typename T>
class KeyedDenseTensorColumn : public DenseTensorColumn {
 public:
  explicit KeyedDenseTensorColumn(const string& name,
                                   const FeatureConfig& config)
      : DenseTensorColumn(name, config),
        strong_hash_(config.strong_hash()),
        key_column_name_(config.key_column_name()) {}

  Status GetFeature(const Input& input, const int64& instance_key,
                    const FeatureConfig& config,
                    const std::vector<Tensor>& input_tensors,
                    Feature* feature) const override {
    const Tensor* input_tensor = nullptr;
    TF_RETURN_IF_ERROR(GetInputTensor(input, config, input_tensors, &input_tensor));
    if (input_tensor == nullptr) {
      return errors::InvalidArgument("Input tensor is null.");
    }
    const auto& input_values = input_tensor->flat<T>();
    const int64 num_values = input_values.size();
    if (num_values == 0) {
      return errors::InvalidArgument("Input tensor is empty.");
    }
    if (instance_key == kInvalidKey) {
      return errors::InvalidArgument("Instance key is invalid.");
    }
    if (key_column_name_.empty()) {
      return errors::InvalidArgument("Key column name is empty.");
    }
    const int64 key_column_index = input_tensor->dims() - 1;
    const Tensor& key_tensor = input_tensor->flat_outer_dims<T>(key_column_index);
    const auto& key_values = key_tensor.flat<T>();
    const int64 num_keys = key_values.size();
    if (num_keys != num_values) {
      return errors::InvalidArgument(
          "Number of keys (", num_keys, ") does not match number of values (",
          num_values, ") in input tensor.");
    }
    const int64 key_index = instance_key * num_keys + key_column_index;
    if (key_index >= num_keys) {
      return errors::InvalidArgument("Instance key is out of range.");
    }
    const T key = key_values(key_index);
    if (strong_hash_) {
      feature->mutable_int64_list()->add_value(StrongKeyedHash(key));
    } else {
      feature->mutable_int64_list()->add_value(Fingerprint64(key));
    }
    return Status::OK();
  }

 private:
  const bool strong_hash_;
  const string key_column_name_;
};

