/*
 * Parse a multi-bulk reply.
 *
 * The function returns the number of elements in the reply.
 * If the reply is not a multi-bulk reply, -1 is returned.
 *
 * The function is safe in the sense that it does not modify the
 * reply object.
 *
 * The function does not handle errors.
 */
int redis_reply_parse_multi_bulk(redisReply *reply) {
    int i, n;

    if (reply->type != REDIS_REPLY_ARRAY)
        return -1;

    n = reply->elements;
    for (i = 0; i < n; i++) {
        if (reply->element[i]->type == REDIS_REPLY_STRING &&
            reply->element[i]->len > 0 &&
            reply->element[i]->str[0] == '-' &&
            reply->element[i]->str[1] == '1') {
            /* overflow */
            return -1;
        }
    }

    return n;
}

