  auto h2session = static_cast<Http2Session *>(user_data);
  auto stream = static_cast<Http2Stream *>(h2session->find_stream(frame->hd.stream_id));
  if (!stream) {
    return;
  }
  stream->rst_received(lib_error_code);
  if (lib_error_code == NGHTTP2_REFUSED_STREAM ||
      lib_error_code == NGHTTP2_CANCEL) {
    h2session->pending_streams_.push_back(stream->get_stream_id());
    h2session->session_state_ = Http2SessionState::Pending;
  } else {
    h2session->session_state_ = Http2SessionState::Closed;
