#include <openssl/err.h>
#include <openssl/cms.h>

int CMS_add0_recipient_key(CMS_ContentInfo *cms, const unsigned char *rid, size_t ridlen, const unsigned char *key, size_t keylen)
{
    CMS_RecipientInfo *ri;
    CMS_RecipientInfo *ri2;
    int i, r = 0;
    int ktype = OBJ_obj2nid(cms->contentType);

    if (ktype == NID_pkcs7_signed)
        ktype = NID_pkcs7_enveloped;

    if (ktype != NID_pkcs7_enveloped && ktype != NID_pkcs7_digest) {
        CMSerr(CMS_F_CMS_ADD0_RECIPIENT_KEY, CMS_R_CONTENT_TYPE_NOT_ENVELOPED_DATA);
        goto err;
    }

    if (!(ri = CMS_add1_recipient_key(cms, rid, ridlen, key, keylen, ktype)))
        goto err;

    /*
     * If we have already encrypted the data we can't add another recipient
     * so we have to make a copy of the recipient list and replace the
     * original with the new one.
     */

    if (cms->d.envelopedData->encryptedContentInfo->recipientinfo) {
        STACK_OF(CMS_RecipientInfo) *rinf = CMS_get0_RecipientInfos(cms);
        STACK_OF(CMS_RecipientInfo) *rinf2 = sk_CMS_RecipientInfo_dup(rinf);
        if (!rinf2)
            goto err;
        if (!CMS_EnvelopedData_set1_recipients(cms, rinf2)) {
            sk_CMS_RecipientInfo_free(rinf2);
            goto err;
        }
        sk_CMS_RecipientInfo_free(rinf);
        rinf = NULL;
    }

    /*
     * If we have already set a key for this recipient then we have to
     * replace it.
     */

    if (cms->d.envelopedData->encryptedContentInfo->cipher) {
        for (i = 0; i < sk_CMS_RecipientInfo_num(rinf); i++) {
            ri2 = sk_CMS_RecipientInfo_value(rinf, i);
            if (CMS_RecipientInfo_type(ri2) == CMS_RECIPINFO_TRANS &&
                ri2->d.ktri->version == 0 &&
                ri2->d.ktri->recip == ri->d.ktri->recip) {
                if (!CMS_RecipientInfo_set0_key(ri2, NULL, NULL, NULL))
                    goto err;
                if (!CMS_RecipientInfo_set0_alg(ri2, NULL, NULL, NULL, 0))
                    goto err;
                if (!CMS_RecipientInfo_ktri_set0_key(ri2, key, keylen, NULL, 0))
                    goto err;
                r = 1;
                break;
            }
        }
    }

    if (!r) {
        if (!CMS_final(cms, NULL, NULL, NULL, 0))
            goto err;
        r = 1;
    }

 err:
    return r;
}

