void KeyedSparseTensorColumn::Lookup(OpKernelContext* ctx, const Tensor& keys,
                                      const Tensor& key_values,
                                      const Tensor& default_value,
                                      Tensor* out_values) const {
  OP_REQUIRES(ctx, TensorShapeUtils::IsMatrix(keys.shape()),
              errors::InvalidArgument("keys should be a matrix"));
  OP_REQUIRES(ctx, TensorShapeUtils::IsMatrix(key_values.shape()),
              errors::InvalidArgument("key_values should be a matrix"));
  OP_REQUIRES(
      ctx, TensorShapeUtils::IsVectorOrHigher(key_values.shape()),
      errors::InvalidArgument("key_values should be at least a vector"));
  OP_REQUIRES(ctx, TensorShapeUtils::IsVector(default_value.shape()),
              errors::InvalidArgument("default_value should be a vector"));
  OP_REQUIRES(ctx, TensorShapeUtils::IsVectorOrHigher(out_values->shape()),
              errors::InvalidArgument("out_values should be at least a vector"));
  OP_REQUIRES(ctx, key_values.dim_size(1) == 2,
              errors::InvalidArgument("key_values should be a matrix with 2 "
                                      "columns, but received shape ",
                                      key_values.shape().DebugString()));
  OP_REQUIRES(ctx, TensorShapeUtils::IsSameSize(keys, out_values),
              errors::InvalidArgument(
                  "keys and out_values should be the same size"));
  OP_REQUIRES(ctx, TensorShapeUtils::IsSameSize(key_values, out_values),
              errors::InvalidArgument(
                  "key_values and out_values should be the same size"));
  OP_REQUIRES(ctx, key_values.dim_size(0) == key_value_map_.size(),
              errors::InvalidArgument(
                  "key_values should have the same size as key_value_map"));
  OP_REQUIRES(ctx, TensorShapeUtils::IsScalar(default_value.shape()),
              errors::InvalidArgument("default_value should be a scalar"));

  auto out_values_flat = out_values->flat<tstring>();
  auto key_values_flat = key_values.shaped<tstring, 2>({key_values.dim_size(0), 2});
  auto keys_flat = keys.shaped<tstring, 2>({keys.dim_size(0), 1});
  auto default_value_flat = default_value.flat<tstring>();

  const int64 N = keys.dim_size(0);
  for (int64 i = 0; i < N; ++i) {
    const tstring& key = keys_flat(i, 0);
    auto iter = key_value_map_.find(key);
    if (iter != key_value_map_.end()) {
      const int64 index = iter->second;
      out_values_flat(i) = key_values_flat(index, 1);
    } else {
      out_values_flat(i) = default_value_flat(0);
    }
  }
}

