#include <hiredis/hiredis.h>

/*
 * redisvFormatCommand is similar to redisFormatCommand, but it also
 * allocates a Redis reply object to be used after the command is executed.
 * The user should later free both the reply object and the command object.
 *
 * The command object should be released with redisCommandFree() and the
 * reply object with redisReplyObjectFree().
 */
redisReply *redisvFormatCommand(redisContext *c, const char *cmd, va_list ap) {
    redisReply *reply;
    char *cmd_to_free = NULL;
    int cmd_len;
    va_list ap_copy;

    va_copy(ap_copy, ap);
    cmd_len = redisvFormatCommand(&cmd_to_free, cmd, ap_copy);
    va_end(ap_copy);
    if (cmd_len == -1) {
        free(cmd_to_free);
        return NULL;
    }

    if (redisAppendCommand(c, cmd_to_free, cmd_len) != REDIS_OK) {
        free(cmd_to_free);
        return NULL;
    }

    if (redisGetReply(c, (void*)&reply) == REDIS_ERR) {
        free(cmd_to_free);
        return NULL;
    }

    free(cmd_to_free);
    return reply;
}

