#include <linux/netfilter/nf_tables.h>
#include <net/netfilter/nf_tables.h>

static int nft_set_desc_concat_parse(struct nft_set_desc *desc,
				       const struct nlattr * const tb[])
{
	struct nft_set_desc_field *field;
	int i;

	if (!tb[NFTA_SET_DESC_CONCAT_MAXLEN])
		return -EINVAL;

	desc->field_len = ntohl(nla_get_be32(tb[NFTA_SET_DESC_CONCAT_MAXLEN]));
	if (desc->field_len > NFT_SET_DESC_MAX_FIELDS)
		return -EINVAL;

	if (!tb[NFTA_SET_DESC_CONCAT_TYPES])
		return -EINVAL;

	desc->field_count = nla_len(tb[NFTA_SET_DESC_CONCAT_TYPES]) /
				sizeof(struct nft_set_desc_field);
	if (desc->field_count > desc->field_len)
		return -EINVAL;

	desc->fields = kmemdup(nla_data(tb[NFTA_SET_DESC_CONCAT_TYPES]),
			       desc->field_count * sizeof(*field), GFP_KERNEL);
	if (!desc->fields)
		return -ENOMEM;

	for (i = 0; i < desc->field_count; i++) {
		field = &desc->fields[i];
		if (field->len > U8_MAX)
			return -EINVAL;
	}

	return 0;
}

