	if (desc->field_count > NFT_SET_MAX_FIELDS)
		return -E2BIG;

	len = nft_reg_load(regs, &desc->field_len, sizeof(desc->field_len));
	for (i = 0; i < desc->field_count; i++) {
		if (len[i] > U8_MAX)
			return -ERANGE;
		desc->total_len += len[i];
