#include <linux/mm.h>
#include <linux/uaccess.h>
#include <linux/vmemdup.h>

static int __bpf_copy_key(struct bpf_map *map, void *key, void *new_key)
{
	int err;

	if (map->map_type->copy_key)
		return map->map_type->copy_key(map, key, new_key);

	if (map->map_type->key_size > PAGE_SIZE)
		return -E2BIG;

	err = vmemdup_user(new_key, key, map->map_type->key_size);
	if (err)
		return err;

	return 0;
}

