#include <sys/types.h>
#include <sys/acl.h>
#include <sys/zfs_acl.h>

int zfs_ace_walk(void *datap, void *cookie, int aclcnt, int flags,
    zfs_acl_type_t type, uint64_t mask) {
    zfs_acl_t *aclp = (zfs_acl_t *)datap;
    zfs_acl_ace_t *acep;
    int error;

    if (aclcnt <= 0)
        return (0);

    acep = zfs_acl_net_ace(aclp, cookie, type, flags, mask);
    if (acep == NULL)
        return (0);

    error = zfs_acl_net_ace_to_zfs(aclp, acep, type);
    if (error)
        return (error);

    return (zfs_acl_next_ace(aclp, acep, aclcnt, flags, type));
}

