#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_WORD_LENGTH 100
#define MAX_SUGGESTIONS 100

int spell_suggest_file(char *preword, char *suggestions[], int max_suggestions) {
  FILE *fp;
  char line[MAX_WORD_LENGTH];
  char *suggest;
  int i = 0;

  if (preword[0] == '\0') {
    return 0;
  }

  fp = mch_fopen((char *)"spell/sug.dic", "r");
  if (fp == NULL) {
    return 0;
  }

  while (i < max_suggestions && (suggest = vim_fgets(line, MAX_WORD_LENGTH, fp)) != NULL) {
    if (strstr(suggest, preword) != NULL) {
      suggestions[i++] = suggest;
    }
  }

  fclose(fp);
  return i;
}

